/// @G_USER_DIRECTORY_MUSIC: the user's Music directory
/// @G_USER_DIRECTORY_PICTURES: the user's Pictures directory
/// @G_USER_DIRECTORY_PUBLIC_SHARE: the user's shared directory
/// @G_USER_DIRECTORY_TEMPLATES: the user's Templates directory
/// @G_USER_DIRECTORY_VIDEOS: the user's Movies directory
/// @G_USER_N_DIRECTORIES: the number of enum values
///
/// These are logical ids for special directories which are defined
/// depending on the platform used. You should use g_get_user_special_dir()
/// to retrieve the full path associated to the logical id.
///
/// The #GUserDirectory enumeration can be extended at later date. Not
/// every platform has a directory for every logical id in this
/// enumeration.
///
/// Since: 2.14
enum GUserDirectory {
  G_USER_DIRECTORY_DESKTOP(0),
  G_USER_DIRECTORY_DOCUMENTS(1),
  G_USER_DIRECTORY_DOWNLOAD(2),
  G_USER_DIRECTORY_MUSIC(3),
  G_USER_DIRECTORY_PICTURES(4),
  G_USER_DIRECTORY_PUBLIC_SHARE(5),
  G_USER_DIRECTORY_TEMPLATES(6),
  G_USER_DIRECTORY_VIDEOS(7),
  G_USER_N_DIRECTORIES(8);

  final int value;
  const GUserDirectory(this.value);

  static GUserDirectory fromValue(int value) => switch (value) {
    0 => G_USER_DIRECTORY_DESKTOP,
    1 => G_USER_DIRECTORY_DOCUMENTS,
    2 => G_USER_DIRECTORY_DOWNLOAD,
    3 => G_USER_DIRECTORY_MUSIC,
    4 => G_USER_DIRECTORY_PICTURES,
    5 => G_USER_DIRECTORY_PUBLIC_SHARE,
    6 => G_USER_DIRECTORY_TEMPLATES,
    7 => G_USER_DIRECTORY_VIDEOS,
    8 => G_USER_N_DIRECTORIES,
    _ => throw ArgumentError("Unknown value for GUserDirectory: $value"),
  };
}

