/// GTimeType:
/// @G_TIME_TYPE_STANDARD: the time is in local standard time
/// @G_TIME_TYPE_DAYLIGHT: the time is in local daylight time
/// @G_TIME_TYPE_UNIVERSAL: the time is in UTC
///
/// Disambiguates a given time in two ways.
///
/// First, specifies if the given time is in universal or local time.
///
/// Second, if the time is in local time, specifies if it is local
/// standard time or local daylight time.  This is important for the case
/// where the same local time occurs twice (during daylight savings time
/// transitions, for example).
enum GTimeType {
  G_TIME_TYPE_STANDARD(0),
  G_TIME_TYPE_DAYLIGHT(1),
  G_TIME_TYPE_UNIVERSAL(2);

  final int value;
  const GTimeType(this.value);

  static GTimeType fromValue(int value) => switch (value) {
    0 => G_TIME_TYPE_STANDARD,
    1 => G_TIME_TYPE_DAYLIGHT,
    2 => G_TIME_TYPE_UNIVERSAL,
    _ => throw ArgumentError("Unknown value for GTimeType: $value"),
  };
}

