/// GNormalizeMode:
/// @G_NORMALIZE_DEFAULT: standardize differences that do not affect the
/// text content, such as the above-mentioned accent representation
/// @G_NORMALIZE_NFD: another name for %G_NORMALIZE_DEFAULT
/// @G_NORMALIZE_DEFAULT_COMPOSE: like %G_NORMALIZE_DEFAULT, but with
/// composed forms rather than a maximally decomposed form
/// @G_NORMALIZE_NFC: another name for %G_NORMALIZE_DEFAULT_COMPOSE
/// @G_NORMALIZE_ALL: beyond %G_NORMALIZE_DEFAULT also standardize the
/// "compatibility" characters in Unicode, such as SUPERSCRIPT THREE
/// to the standard forms (in this case DIGIT THREE). Formatting
/// information may be lost but for most text operations such
/// characters should be considered the same
/// @G_NORMALIZE_NFKD: another name for %G_NORMALIZE_ALL
/// @G_NORMALIZE_ALL_COMPOSE: like %G_NORMALIZE_ALL, but with composed
/// forms rather than a maximally decomposed form
/// @G_NORMALIZE_NFKC: another name for %G_NORMALIZE_ALL_COMPOSE
///
/// Defines how a Unicode string is transformed in a canonical
/// form, standardizing such issues as whether a character with
/// an accent is represented as a base character and combining
/// accent or as a single precomposed character. Unicode strings
/// should generally be normalized before comparing them.
enum GNormalizeMode {
  G_NORMALIZE_DEFAULT(0),
  G_NORMALIZE_DEFAULT_COMPOSE(1),
  G_NORMALIZE_ALL(2),
  G_NORMALIZE_ALL_COMPOSE(3);

  static const G_NORMALIZE_NFD = G_NORMALIZE_DEFAULT;
  static const G_NORMALIZE_NFC = G_NORMALIZE_DEFAULT_COMPOSE;
  static const G_NORMALIZE_NFKD = G_NORMALIZE_ALL;
  static const G_NORMALIZE_NFKC = G_NORMALIZE_ALL_COMPOSE;

  final int value;
  const GNormalizeMode(this.value);

  static GNormalizeMode fromValue(int value) => switch (value) {
    0 => G_NORMALIZE_DEFAULT,
    1 => G_NORMALIZE_DEFAULT_COMPOSE,
    2 => G_NORMALIZE_ALL,
    3 => G_NORMALIZE_ALL_COMPOSE,
    _ => throw ArgumentError("Unknown value for GNormalizeMode: $value"),
  };

  @override
  String toString() {
    if (this == G_NORMALIZE_DEFAULT)
      return "GNormalizeMode.G_NORMALIZE_DEFAULT, GNormalizeMode.G_NORMALIZE_NFD";
    if (this == G_NORMALIZE_DEFAULT_COMPOSE)
      return "GNormalizeMode.G_NORMALIZE_DEFAULT_COMPOSE, GNormalizeMode.G_NORMALIZE_NFC";
    if (this == G_NORMALIZE_ALL)
      return "GNormalizeMode.G_NORMALIZE_ALL, GNormalizeMode.G_NORMALIZE_NFKD";
    if (this == G_NORMALIZE_ALL_COMPOSE)
      return "GNormalizeMode.G_NORMALIZE_ALL_COMPOSE, GNormalizeMode.G_NORMALIZE_NFKC";
    return super.toString();
  }
}

