        ffi.Pointer<ffi.Pointer<gchar>> attribute_values,
        gpointer user_data,
        ffi.Pointer<ffi.Pointer<GError>> error,
      )
    >
  >
  start_element;

  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        ffi.Pointer<GMarkupParseContext> context,
        ffi.Pointer<gchar> element_name,
        gpointer user_data,
        ffi.Pointer<ffi.Pointer<GError>> error,
      )
    >
  >
  end_element;

  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
