/// GRegexCompileFlags:
/// @G_REGEX_DEFAULT: No special options set. Since: 2.74
/// @G_REGEX_CASELESS: Letters in the pattern match both upper- and
/// lowercase letters. This option can be changed within a pattern
/// by a "(?i)" option setting.
/// @G_REGEX_MULTILINE: By default, GRegex treats the strings as consisting
/// of a single line of characters (even if it actually contains
/// newlines). The "start of line" metacharacter ("^") matches only
/// at the start of the string, while the "end of line" metacharacter
/// ("$") matches only at the end of the string, or before a terminating
/// newline (unless %G_REGEX_DOLLAR_ENDONLY is set). When
/// %G_REGEX_MULTILINE is set, the "start of line" and "end of line"
/// constructs match immediately following or immediately before any
/// newline in the string, respectively, as well as at the very start
/// and end. This can be changed within a pattern by a "(?m)" option
/// setting.
/// @G_REGEX_DOTALL: A dot metacharacter (".") in the pattern matches all
/// characters, including newlines. Without it, newlines are excluded.
/// This option can be changed within a pattern by a ("?s") option setting.
/// @G_REGEX_EXTENDED: Whitespace data characters in the pattern are
/// totally ignored except when escaped or inside a character class.
/// Whitespace does not include the VT character (code 11). In addition,
/// characters between an unescaped "#" outside a character class and
/// the next newline character, inclusive, are also ignored. This can
/// be changed within a pattern by a "(?x)" option setting.
/// @G_REGEX_ANCHORED: The pattern is forced to be "anchored", that is,
/// it is constrained to match only at the first matching point in the
/// string that is being searched. This effect can also be achieved by
/// appropriate constructs in the pattern itself such as the "^"
/// metacharacter.
/// @G_REGEX_DOLLAR_ENDONLY: A dollar metacharacter ("$") in the pattern
/// matches only at the end of the string. Without this option, a
/// dollar also matches immediately before the final character if
/// it is a newline (but not before any other newlines). This option
/// is ignored if %G_REGEX_MULTILINE is set.
/// @G_REGEX_UNGREEDY: Inverts the "greediness" of the quantifiers so that
/// they are not greedy by default, but become greedy if followed by "?".
/// It can also be set by a "(?U)" option setting within the pattern.
/// @G_REGEX_RAW: Usually strings must be valid UTF-8 strings, using this
/// flag they are considered as a raw sequence of bytes.
/// @G_REGEX_NO_AUTO_CAPTURE: Disables the use of numbered capturing
/// parentheses in the pattern. Any opening parenthesis that is not
/// followed by "?" behaves as if it were followed by "?:" but named
/// parentheses can still be used for capturing (and they acquire numbers
/// in the usual way).
/// @G_REGEX_OPTIMIZE: Since 2.74 and the port to pcre2, requests JIT
/// compilation, which, if the just-in-time compiler is available, further
/// processes a compiled pattern into machine code that executes much
/// faster. However, it comes at the cost of extra processing before the
/// match is performed, so it is most beneficial to use this when the same
/// compiled pattern is used for matching many times. Before 2.74 this
/// option used the built-in non-JIT optimizations in pcre1.
/// @G_REGEX_FIRSTLINE: Limits an unanchored pattern to match before (or at) the
/// first newline. Since: 2.34
/// @G_REGEX_DUPNAMES: Names used to identify capturing subpatterns need not
/// be unique. This can be helpful for certain types of pattern when it
/// is known that only one instance of the named subpattern can ever be
/// matched.
/// @G_REGEX_NEWLINE_CR: Usually any newline character or character sequence is
/// recognized. If this option is set, the only recognized newline character
/// is '\r'.
/// @G_REGEX_NEWLINE_LF: Usually any newline character or character sequence is
/// recognized. If this option is set, the only recognized newline character
/// is '\n'.
/// @G_REGEX_NEWLINE_CRLF: Usually any newline character or character sequence is
/// recognized. If this option is set, the only recognized newline character
/// sequence is '\r\n'.
/// @G_REGEX_NEWLINE_ANYCRLF: Usually any newline character or character sequence
/// is recognized. If this option is set, the only recognized newline character
/// sequences are '\r', '\n', and '\r\n'. Since: 2.34
/// @G_REGEX_BSR_ANYCRLF: Usually any newline character or character sequence
/// is recognised. If this option is set, then "\R" only recognizes the newline
/// characters '\r', '\n' and '\r\n'. Since: 2.34
/// @G_REGEX_JAVASCRIPT_COMPAT: Changes behaviour so that it is compatible with
/// JavaScript rather than PCRE. Since GLib 2.74 this is no longer supported,
/// as libpcre2 does not support it. Since: 2.34 Deprecated: 2.74
///
/// Flags specifying compile-time options.
///
/// Since: 2.14
enum GRegexCompileFlags {
  G_REGEX_DEFAULT(0),
  G_REGEX_CASELESS(1),
  G_REGEX_MULTILINE(2),
  G_REGEX_DOTALL(4),
  G_REGEX_EXTENDED(8),
  G_REGEX_ANCHORED(16),
  G_REGEX_DOLLAR_ENDONLY(32),
  G_REGEX_UNGREEDY(512),
  G_REGEX_RAW(2048),
  G_REGEX_NO_AUTO_CAPTURE(4096),
  G_REGEX_OPTIMIZE(8192),
  G_REGEX_FIRSTLINE(262144),
  G_REGEX_DUPNAMES(524288),
  G_REGEX_NEWLINE_CR(1048576),
  G_REGEX_NEWLINE_LF(2097152),
  G_REGEX_NEWLINE_CRLF(3145728),
  G_REGEX_NEWLINE_ANYCRLF(5242880),
  G_REGEX_BSR_ANYCRLF(8388608),
  G_REGEX_JAVASCRIPT_COMPAT(33554432);

  final int value;
  const GRegexCompileFlags(this.value);

  static GRegexCompileFlags fromValue(int value) => switch (value) {
    0 => G_REGEX_DEFAULT,
    1 => G_REGEX_CASELESS,
    2 => G_REGEX_MULTILINE,
    4 => G_REGEX_DOTALL,
    8 => G_REGEX_EXTENDED,
    16 => G_REGEX_ANCHORED,
    32 => G_REGEX_DOLLAR_ENDONLY,
    512 => G_REGEX_UNGREEDY,
    2048 => G_REGEX_RAW,
    4096 => G_REGEX_NO_AUTO_CAPTURE,
    8192 => G_REGEX_OPTIMIZE,
    262144 => G_REGEX_FIRSTLINE,
    524288 => G_REGEX_DUPNAMES,
    1048576 => G_REGEX_NEWLINE_CR,
    2097152 => G_REGEX_NEWLINE_LF,
    3145728 => G_REGEX_NEWLINE_CRLF,
    5242880 => G_REGEX_NEWLINE_ANYCRLF,
    8388608 => G_REGEX_BSR_ANYCRLF,
    33554432 => G_REGEX_JAVASCRIPT_COMPAT,
    _ => throw ArgumentError("Unknown value for GRegexCompileFlags: $value"),
  };
}

/// GRegexMatchFlags:
/// @G_REGEX_MATCH_DEFAULT: No special options set. Since: 2.74
/// @G_REGEX_MATCH_ANCHORED: The pattern is forced to be "anchored", that is,
/// it is constrained to match only at the first matching point in the
/// string that is being searched. This effect can also be achieved by
/// appropriate constructs in the pattern itself such as the "^"
/// metacharacter.
/// @G_REGEX_MATCH_NOTBOL: Specifies that first character of the string is
/// not the beginning of a line, so the circumflex metacharacter should
/// not match before it. Setting this without %G_REGEX_MULTILINE (at
/// compile time) causes circumflex never to match. This option affects
/// only the behaviour of the circumflex metacharacter, it does not
/// affect "\A".
/// @G_REGEX_MATCH_NOTEOL: Specifies that the end of the subject string is
/// not the end of a line, so the dollar metacharacter should not match
/// it nor (except in multiline mode) a newline immediately before it.
/// Setting this without %G_REGEX_MULTILINE (at compile time) causes
/// dollar never to match. This option affects only the behaviour of
/// the dollar metacharacter, it does not affect "\Z" or "\z".
/// @G_REGEX_MATCH_NOTEMPTY: An empty string is not considered to be a valid
/// match if this option is set. If there are alternatives in the pattern,
/// they are tried. If all the alternatives match the empty string, the
/// entire match fails. For example, if the pattern "a?b?" is applied to
/// a string not beginning with "a" or "b", it matches the empty string
/// at the start of the string. With this flag set, this match is not
/// valid, so GRegex searches further into the string for occurrences
/// of "a" or "b".
/// @G_REGEX_MATCH_PARTIAL: Turns on the partial matching feature, for more
/// documentation on partial matching see g_match_info_is_partial_match().
/// @G_REGEX_MATCH_NEWLINE_CR: Overrides the newline definition set when
/// creating a new #GRegex, setting the '\r' character as line terminator.
/// @G_REGEX_MATCH_NEWLINE_LF: Overrides the newline definition set when
/// creating a new #GRegex, setting the '\n' character as line terminator.
/// @G_REGEX_MATCH_NEWLINE_CRLF: Overrides the newline definition set when
/// creating a new #GRegex, setting the '\r\n' characters sequence as line terminator.
/// @G_REGEX_MATCH_NEWLINE_ANY: Overrides the newline definition set when
/// creating a new #GRegex, any Unicode newline sequence
/// is recognised as a newline. These are '\r', '\n' and '\rn', and the
/// single characters U+000B LINE TABULATION, U+000C FORM FEED (FF),
/// U+0085 NEXT LINE (NEL), U+2028 LINE SEPARATOR and
/// U+2029 PARAGRAPH SEPARATOR.
/// @G_REGEX_MATCH_NEWLINE_ANYCRLF: Overrides the newline definition set when
/// creating a new #GRegex; any '\r', '\n', or '\r\n' character sequence
/// is recognized as a newline. Since: 2.34
/// @G_REGEX_MATCH_BSR_ANYCRLF: Overrides the newline definition for "\R" set when
/// creating a new #GRegex; only '\r', '\n', or '\r\n' character sequences
/// are recognized as a newline by "\R". Since: 2.34
/// @G_REGEX_MATCH_BSR_ANY: Overrides the newline definition for "\R" set when
/// creating a new #GRegex; any Unicode newline character or character sequence
/// are recognized as a newline by "\R". These are '\r', '\n' and '\rn', and the
/// single characters U+000B LINE TABULATION, U+000C FORM FEED (FF),
/// U+0085 NEXT LINE (NEL), U+2028 LINE SEPARATOR and
/// U+2029 PARAGRAPH SEPARATOR. Since: 2.34
/// @G_REGEX_MATCH_PARTIAL_SOFT: An alias for %G_REGEX_MATCH_PARTIAL. Since: 2.34
/// @G_REGEX_MATCH_PARTIAL_HARD: Turns on the partial matching feature. In contrast to
/// to %G_REGEX_MATCH_PARTIAL_SOFT, this stops matching as soon as a partial match
/// is found, without continuing to search for a possible complete match. See
/// g_match_info_is_partial_match() for more information. Since: 2.34
/// @G_REGEX_MATCH_NOTEMPTY_ATSTART: Like %G_REGEX_MATCH_NOTEMPTY, but only applied to
/// the start of the matched string. For anchored
/// patterns this can only happen for pattern containing "\K". Since: 2.34
///
/// Flags specifying match-time options.
///
/// Since: 2.14
enum GRegexMatchFlags {
  G_REGEX_MATCH_DEFAULT(0),
  G_REGEX_MATCH_ANCHORED(16),
  G_REGEX_MATCH_NOTBOL(128),
  G_REGEX_MATCH_NOTEOL(256),
  G_REGEX_MATCH_NOTEMPTY(1024),
  G_REGEX_MATCH_PARTIAL(32768),
  G_REGEX_MATCH_NEWLINE_CR(1048576),
  G_REGEX_MATCH_NEWLINE_LF(2097152),
  G_REGEX_MATCH_NEWLINE_CRLF(3145728),
  G_REGEX_MATCH_NEWLINE_ANY(4194304),
  G_REGEX_MATCH_NEWLINE_ANYCRLF(5242880),
  G_REGEX_MATCH_BSR_ANYCRLF(8388608),
  G_REGEX_MATCH_BSR_ANY(16777216),
  G_REGEX_MATCH_PARTIAL_HARD(134217728),
  G_REGEX_MATCH_NOTEMPTY_ATSTART(268435456);

  static const G_REGEX_MATCH_PARTIAL_SOFT = G_REGEX_MATCH_PARTIAL;

  final int value;
  const GRegexMatchFlags(this.value);

  static GRegexMatchFlags fromValue(int value) => switch (value) {
    0 => G_REGEX_MATCH_DEFAULT,
    16 => G_REGEX_MATCH_ANCHORED,
    128 => G_REGEX_MATCH_NOTBOL,
    256 => G_REGEX_MATCH_NOTEOL,
    1024 => G_REGEX_MATCH_NOTEMPTY,
    32768 => G_REGEX_MATCH_PARTIAL,
    1048576 => G_REGEX_MATCH_NEWLINE_CR,
    2097152 => G_REGEX_MATCH_NEWLINE_LF,
    3145728 => G_REGEX_MATCH_NEWLINE_CRLF,
    4194304 => G_REGEX_MATCH_NEWLINE_ANY,
    5242880 => G_REGEX_MATCH_NEWLINE_ANYCRLF,
    8388608 => G_REGEX_MATCH_BSR_ANYCRLF,
    16777216 => G_REGEX_MATCH_BSR_ANY,
    134217728 => G_REGEX_MATCH_PARTIAL_HARD,
    268435456 => G_REGEX_MATCH_NOTEMPTY_ATSTART,
    _ => throw ArgumentError("Unknown value for GRegexMatchFlags: $value"),
  };

  @override
  String toString() {
    if (this == G_REGEX_MATCH_PARTIAL)
      return "GRegexMatchFlags.G_REGEX_MATCH_PARTIAL, GRegexMatchFlags.G_REGEX_MATCH_PARTIAL_SOFT";
