/// in a future version. A warning will be generated if it is connected while
/// running with G_ENABLE_DIAGNOSTIC=1.  Since 2.32.
/// @G_SIGNAL_ACCUMULATOR_FIRST_RUN: Only used in #GSignalAccumulator accumulator
/// functions for the #GSignalInvocationHint::run_type field to mark the first
/// call to the accumulator function for a signal emission.  Since 2.68.
///
/// The signal flags are used to specify a signal's behaviour.
enum GSignalFlags {
  G_SIGNAL_RUN_FIRST(1),
  G_SIGNAL_RUN_LAST(2),
  G_SIGNAL_RUN_CLEANUP(4),
  G_SIGNAL_NO_RECURSE(8),
  G_SIGNAL_DETAILED(16),
  G_SIGNAL_ACTION(32),
  G_SIGNAL_NO_HOOKS(64),
  G_SIGNAL_MUST_COLLECT(128),
  G_SIGNAL_DEPRECATED(256),
  G_SIGNAL_ACCUMULATOR_FIRST_RUN(131072);

  final int value;
  const GSignalFlags(this.value);

  static GSignalFlags fromValue(int value) => switch (value) {
    1 => G_SIGNAL_RUN_FIRST,
    2 => G_SIGNAL_RUN_LAST,
    4 => G_SIGNAL_RUN_CLEANUP,
    8 => G_SIGNAL_NO_RECURSE,
    16 => G_SIGNAL_DETAILED,
    32 => G_SIGNAL_ACTION,
    64 => G_SIGNAL_NO_HOOKS,
    128 => G_SIGNAL_MUST_COLLECT,
    256 => G_SIGNAL_DEPRECATED,
    131072 => G_SIGNAL_ACCUMULATOR_FIRST_RUN,
    _ => throw ArgumentError("Unknown value for GSignalFlags: $value"),
  };
}

