  };
}

/// PopplerPrintFlags:
/// @POPPLER_PRINT_DOCUMENT: print main document contents
/// @POPPLER_PRINT_MARKUP_ANNOTS: print document and markup annotations
/// @POPPLER_PRINT_STAMP_ANNOTS_ONLY: print document and only stamp annotations
/// @POPPLER_PRINT_ALL: print main document contents and all markup annotations
///
/// Printing flags
///
/// Since: 0.16
enum PopplerPrintFlags {
  POPPLER_PRINT_DOCUMENT(0),
  POPPLER_PRINT_MARKUP_ANNOTS(1),
  POPPLER_PRINT_STAMP_ANNOTS_ONLY(2);

  static const POPPLER_PRINT_ALL = POPPLER_PRINT_MARKUP_ANNOTS;

  final int value;
  const PopplerPrintFlags(this.value);

  static PopplerPrintFlags fromValue(int value) => switch (value) {
    0 => POPPLER_PRINT_DOCUMENT,
    1 => POPPLER_PRINT_MARKUP_ANNOTS,
    2 => POPPLER_PRINT_STAMP_ANNOTS_ONLY,
    _ => throw ArgumentError("Unknown value for PopplerPrintFlags: $value"),
  };

  @override
  String toString() {
    if (this == POPPLER_PRINT_MARKUP_ANNOTS)
      return "PopplerPrintFlags.POPPLER_PRINT_MARKUP_ANNOTS, PopplerPrintFlags.POPPLER_PRINT_ALL";
    return super.toString();
  }
}

/// PopplerFindFlags:
/// @POPPLER_FIND_DEFAULT: use default search settings
/// @POPPLER_FIND_CASE_SENSITIVE: do case sensitive search
/// @POPPLER_FIND_BACKWARDS: search backwards
/// @POPPLER_FIND_WHOLE_WORDS_ONLY: search only whole words
/// @POPPLER_FIND_IGNORE_DIACRITICS: do diacritics insensitive search,
/// i.e. ignore accents, umlauts, diaeresis,etc. while matching. This
/// option will be ignored if the search term is not pure ascii. Since 0.73.
/// @POPPLER_FIND_MULTILINE: allows to match on text spanning from
/// end of a line to the next line. (Currently it won't match on text spanning
/// more than two lines.) Automatically ignores hyphen at end of line, and
/// allows whitespace in search term to match on newline char. Since: 21.05.0.
///
/// Flags using while searching text in a page
///
/// Since: 0.22
enum PopplerFindFlags {
  POPPLER_FIND_DEFAULT(0),
  POPPLER_FIND_CASE_SENSITIVE(1),
  POPPLER_FIND_BACKWARDS(2),
  POPPLER_FIND_WHOLE_WORDS_ONLY(4),
  POPPLER_FIND_IGNORE_DIACRITICS(8),
  POPPLER_FIND_MULTILINE(16);

  final int value;
  const PopplerFindFlags(this.value);

  static PopplerFindFlags fromValue(int value) => switch (value) {
    0 => POPPLER_FIND_DEFAULT,
    1 => POPPLER_FIND_CASE_SENSITIVE,
    2 => POPPLER_FIND_BACKWARDS,
    4 => POPPLER_FIND_WHOLE_WORDS_ONLY,
    8 => POPPLER_FIND_IGNORE_DIACRITICS,
    16 => POPPLER_FIND_MULTILINE,
    _ => throw ArgumentError("Unknown value for PopplerFindFlags: $value"),
  };
}

