/// PopplerAction:
///
/// A generic wrapper for actions that exposes only #PopplerActionType.
final class _PopplerAction extends ffi.Union {
  @ffi.UnsignedInt()
  external int typeAsInt;

  PopplerActionType get type => PopplerActionType.fromValue(typeAsInt);

  external PopplerActionAny any;

  external PopplerActionGotoDest goto_dest;

  external PopplerActionGotoRemote goto_remote;

  external PopplerActionLaunch launch;

  external PopplerActionUri uri;

  external PopplerActionNamed named;

  external PopplerActionMovie movie;

  external PopplerActionRendition rendition;

  external PopplerActionOCGState ocg_state;

  external PopplerActionJavascript javascript;

  external PopplerActionResetForm reset_form;
}

/// PopplerActionType:
/// @POPPLER_ACTION_UNKNOWN: unknown action
/// @POPPLER_ACTION_NONE: no action specified
/// @POPPLER_ACTION_GOTO_DEST: go to destination
/// @POPPLER_ACTION_GOTO_REMOTE: go to destination in another document
/// @POPPLER_ACTION_LAUNCH: launch app (or open document)
/// @POPPLER_ACTION_URI: URI
/// @POPPLER_ACTION_NAMED: predefined action
/// @POPPLER_ACTION_MOVIE: play movies. Since 0.14
/// @POPPLER_ACTION_RENDITION: play multimedia content. Since 0.14
/// @POPPLER_ACTION_OCG_STATE: state of layer. Since 0.14
/// @POPPLER_ACTION_JAVASCRIPT: Javascript. Since 0.18
/// @POPPLER_ACTION_RESET_FORM: resets form. Since 0.90
///
/// Action types
enum PopplerActionType {
  POPPLER_ACTION_UNKNOWN(0),
  POPPLER_ACTION_NONE(1),
  POPPLER_ACTION_GOTO_DEST(2),
  POPPLER_ACTION_GOTO_REMOTE(3),
  POPPLER_ACTION_LAUNCH(4),
  POPPLER_ACTION_URI(5),
  POPPLER_ACTION_NAMED(6),
  POPPLER_ACTION_MOVIE(7),
  POPPLER_ACTION_RENDITION(8),
  POPPLER_ACTION_OCG_STATE(9),
  POPPLER_ACTION_JAVASCRIPT(10),
  POPPLER_ACTION_RESET_FORM(11);

  final int value;
  const PopplerActionType(this.value);

  static PopplerActionType fromValue(int value) => switch (value) {
    0 => POPPLER_ACTION_UNKNOWN,
    1 => POPPLER_ACTION_NONE,
    2 => POPPLER_ACTION_GOTO_DEST,
    3 => POPPLER_ACTION_GOTO_REMOTE,
    4 => POPPLER_ACTION_LAUNCH,
    5 => POPPLER_ACTION_URI,
    6 => POPPLER_ACTION_NAMED,
    7 => POPPLER_ACTION_MOVIE,
    8 => POPPLER_ACTION_RENDITION,
    9 => POPPLER_ACTION_OCG_STATE,
    10 => POPPLER_ACTION_JAVASCRIPT,
    11 => POPPLER_ACTION_RESET_FORM,
    _ => throw ArgumentError("Unknown value for PopplerActionType: $value"),
  };
}

