  };
}

/// GFileCopyFlags:
/// @G_FILE_COPY_NONE: No flags set.
/// @G_FILE_COPY_OVERWRITE: Overwrite any existing files
/// @G_FILE_COPY_BACKUP: Make a backup of any existing files.
/// @G_FILE_COPY_NOFOLLOW_SYMLINKS: Don't follow symlinks.
/// @G_FILE_COPY_ALL_METADATA: Copy all file metadata instead of just default set used for copy (see #GFileInfo).
/// @G_FILE_COPY_NO_FALLBACK_FOR_MOVE: Don't use copy and delete fallback if native move not supported.
/// @G_FILE_COPY_TARGET_DEFAULT_PERMS: Leaves target file with default perms, instead of setting the source file perms.
/// @G_FILE_COPY_TARGET_DEFAULT_MODIFIED_TIME: Use default modification
/// timestamps instead of copying them from the source file. Since 2.80
///
/// Flags used when copying or moving files.
enum GFileCopyFlags {
  G_FILE_COPY_NONE(0),
  G_FILE_COPY_OVERWRITE(1),
  G_FILE_COPY_BACKUP(2),
  G_FILE_COPY_NOFOLLOW_SYMLINKS(4),
  G_FILE_COPY_ALL_METADATA(8),
  G_FILE_COPY_NO_FALLBACK_FOR_MOVE(16),
  G_FILE_COPY_TARGET_DEFAULT_PERMS(32),
  G_FILE_COPY_TARGET_DEFAULT_MODIFIED_TIME(64);

  final int value;
  const GFileCopyFlags(this.value);

  static GFileCopyFlags fromValue(int value) => switch (value) {
    0 => G_FILE_COPY_NONE,
    1 => G_FILE_COPY_OVERWRITE,
    2 => G_FILE_COPY_BACKUP,
    4 => G_FILE_COPY_NOFOLLOW_SYMLINKS,
    8 => G_FILE_COPY_ALL_METADATA,
    16 => G_FILE_COPY_NO_FALLBACK_FOR_MOVE,
    32 => G_FILE_COPY_TARGET_DEFAULT_PERMS,
    64 => G_FILE_COPY_TARGET_DEFAULT_MODIFIED_TIME,
    _ => throw ArgumentError("Unknown value for GFileCopyFlags: $value"),
  };
}

/// GFileMonitorFlags:
/// @G_FILE_MONITOR_NONE: No flags set.
/// @G_FILE_MONITOR_WATCH_MOUNTS: Watch for mount events.
/// @G_FILE_MONITOR_SEND_MOVED: Pair DELETED and CREATED events caused
/// by file renames (moves) and send a single G_FILE_MONITOR_EVENT_MOVED
/// event instead (NB: not supported on all backends; the default
/// behaviour -without specifying this flag- is to send single DELETED
/// and CREATED events).  Deprecated since 2.46: use
/// %G_FILE_MONITOR_WATCH_MOVES instead.
/// @G_FILE_MONITOR_WATCH_HARD_LINKS: Watch for changes to the file made
/// via another hard link. Since 2.36.
/// @G_FILE_MONITOR_WATCH_MOVES: Watch for rename operations on a
/// monitored directory.  This causes %G_FILE_MONITOR_EVENT_RENAMED,
/// %G_FILE_MONITOR_EVENT_MOVED_IN and %G_FILE_MONITOR_EVENT_MOVED_OUT
/// events to be emitted when possible.  Since: 2.46.
///
/// Flags used to set what a #GFileMonitor will watch for.
enum GFileMonitorFlags {
  G_FILE_MONITOR_NONE(0),
  G_FILE_MONITOR_WATCH_MOUNTS(1),
  G_FILE_MONITOR_SEND_MOVED(2),
  G_FILE_MONITOR_WATCH_HARD_LINKS(4),
  G_FILE_MONITOR_WATCH_MOVES(8);

  final int value;
  const GFileMonitorFlags(this.value);

  static GFileMonitorFlags fromValue(int value) => switch (value) {
    0 => G_FILE_MONITOR_NONE,
    1 => G_FILE_MONITOR_WATCH_MOUNTS,
    2 => G_FILE_MONITOR_SEND_MOVED,
    4 => G_FILE_MONITOR_WATCH_HARD_LINKS,
    8 => G_FILE_MONITOR_WATCH_MOVES,
    _ => throw ArgumentError("Unknown value for GFileMonitorFlags: $value"),
  };
}

/// GFileType:
/// @G_FILE_TYPE_UNKNOWN: File's type is unknown.
/// @G_FILE_TYPE_REGULAR: File handle represents a regular file.
/// @G_FILE_TYPE_DIRECTORY: File handle represents a directory.
/// @G_FILE_TYPE_SYMBOLIC_LINK: File handle represents a symbolic link
/// (Unix systems).
/// @G_FILE_TYPE_SPECIAL: File is a "special" file, such as a socket, fifo,
/// block device, or character device.
/// @G_FILE_TYPE_SHORTCUT: File is a shortcut (Windows systems).
/// @G_FILE_TYPE_MOUNTABLE: File is a mountable location.
///
/// Indicates the file's on-disk type.
///
/// On Windows systems a file will never have %G_FILE_TYPE_SYMBOLIC_LINK type;
/// use #GFileInfo and %G_FILE_ATTRIBUTE_STANDARD_IS_SYMLINK to determine
/// whether a file is a symlink or not. This is due to the fact that NTFS does
/// not have a single filesystem object type for symbolic links - it has
/// files that symlink to files, and directories that symlink to directories.
/// #GFileType enumeration cannot precisely represent this important distinction,
/// which is why all Windows symlinks will continue to be reported as
/// %G_FILE_TYPE_REGULAR or %G_FILE_TYPE_DIRECTORY.
enum GFileType {
  G_FILE_TYPE_UNKNOWN(0),
  G_FILE_TYPE_REGULAR(1),
  G_FILE_TYPE_DIRECTORY(2),
  G_FILE_TYPE_SYMBOLIC_LINK(3),
  G_FILE_TYPE_SPECIAL(4),
  G_FILE_TYPE_SHORTCUT(5),
  G_FILE_TYPE_MOUNTABLE(6);

  final int value;
  const GFileType(this.value);

  static GFileType fromValue(int value) => switch (value) {
    0 => G_FILE_TYPE_UNKNOWN,
    1 => G_FILE_TYPE_REGULAR,
    2 => G_FILE_TYPE_DIRECTORY,
    3 => G_FILE_TYPE_SYMBOLIC_LINK,
    4 => G_FILE_TYPE_SPECIAL,
    5 => G_FILE_TYPE_SHORTCUT,
    6 => G_FILE_TYPE_MOUNTABLE,
    _ => throw ArgumentError("Unknown value for GFileType: $value"),
  };
}

/// GFilesystemPreviewType:
