/// information is send by the mounting operation.
enum GMountOperationResult {
  G_MOUNT_OPERATION_HANDLED(0),
  G_MOUNT_OPERATION_ABORTED(1),
  G_MOUNT_OPERATION_UNHANDLED(2);

  final int value;
  const GMountOperationResult(this.value);

