  const GUnixSocketAddressType(this.value);

  static GUnixSocketAddressType fromValue(int value) => switch (value) {
    0 => G_UNIX_SOCKET_ADDRESS_INVALID,
    1 => G_UNIX_SOCKET_ADDRESS_ANONYMOUS,
