  const GCredentialsType(this.value);

  static GCredentialsType fromValue(int value) => switch (value) {
    0 => G_CREDENTIALS_TYPE_INVALID,
    1 => G_CREDENTIALS_TYPE_LINUX_UCRED,
    2 => G_CREDENTIALS_TYPE_FREEBSD_CMSGCRED,
    3 => G_CREDENTIALS_TYPE_OPENBSD_SOCKPEERCRED,
