/// GApplicationFlags:
/// @G_APPLICATION_FLAGS_NONE: Default. Deprecated in 2.74, use
/// %G_APPLICATION_DEFAULT_FLAGS instead
/// @G_APPLICATION_DEFAULT_FLAGS: Default flags. Since: 2.74
/// @G_APPLICATION_IS_SERVICE: Run as a service. In this mode, registration
/// fails if the service is already running, and the application
/// will initially wait up to 10 seconds for an initial activation
/// message to arrive.
/// @G_APPLICATION_IS_LAUNCHER: Don't try to become the primary instance.
/// @G_APPLICATION_HANDLES_OPEN: This application handles opening files (in
/// the primary instance). Note that this flag only affects the default
/// implementation of local_command_line(), and has no effect if
/// %G_APPLICATION_HANDLES_COMMAND_LINE is given.
/// See g_application_run() for details.
/// @G_APPLICATION_HANDLES_COMMAND_LINE: This application handles command line
/// arguments (in the primary instance). Note that this flag only affect
/// the default implementation of local_command_line().
/// See g_application_run() for details.
/// @G_APPLICATION_SEND_ENVIRONMENT: Send the environment of the
/// launching process to the primary instance. Set this flag if your
/// application is expected to behave differently depending on certain
/// environment variables. For instance, an editor might be expected
/// to use the `GIT_COMMITTER_NAME` environment variable
/// when editing a git commit message. The environment is available
/// to the #GApplication::command-line signal handler, via
/// g_application_command_line_getenv().
/// @G_APPLICATION_NON_UNIQUE: Make no attempts to do any of the typical
/// single-instance application negotiation, even if the application
/// ID is given.  The application neither attempts to become the
/// owner of the application ID nor does it check if an existing
/// owner already exists.  Everything occurs in the local process.
/// Since: 2.30.
/// @G_APPLICATION_CAN_OVERRIDE_APP_ID: Allow users to override the
/// application ID from the command line with `--gapplication-app-id`.
/// Since: 2.48
/// @G_APPLICATION_ALLOW_REPLACEMENT: Allow another instance to take over
/// the bus name. Since: 2.60
/// @G_APPLICATION_REPLACE: Take over from another instance. This flag is
/// usually set by passing `--gapplication-replace` on the commandline.
/// Since: 2.60
///
/// Flags used to define the behaviour of a #GApplication.
///
/// Since: 2.28
enum GApplicationFlags {
  G_APPLICATION_FLAGS_NONE(0),
  G_APPLICATION_IS_SERVICE(1),
  G_APPLICATION_IS_LAUNCHER(2),
  G_APPLICATION_HANDLES_OPEN(4),
  G_APPLICATION_HANDLES_COMMAND_LINE(8),
  G_APPLICATION_SEND_ENVIRONMENT(16),
  G_APPLICATION_NON_UNIQUE(32),
  G_APPLICATION_CAN_OVERRIDE_APP_ID(64),
  G_APPLICATION_ALLOW_REPLACEMENT(128),
  G_APPLICATION_REPLACE(256);

  static const G_APPLICATION_DEFAULT_FLAGS = G_APPLICATION_FLAGS_NONE;

  final int value;
  const GApplicationFlags(this.value);

  static GApplicationFlags fromValue(int value) => switch (value) {
    0 => G_APPLICATION_FLAGS_NONE,
    1 => G_APPLICATION_IS_SERVICE,
    2 => G_APPLICATION_IS_LAUNCHER,
    4 => G_APPLICATION_HANDLES_OPEN,
    8 => G_APPLICATION_HANDLES_COMMAND_LINE,
    16 => G_APPLICATION_SEND_ENVIRONMENT,
    32 => G_APPLICATION_NON_UNIQUE,
    64 => G_APPLICATION_CAN_OVERRIDE_APP_ID,
    128 => G_APPLICATION_ALLOW_REPLACEMENT,
    256 => G_APPLICATION_REPLACE,
    _ => throw ArgumentError("Unknown value for GApplicationFlags: $value"),
  };

  @override
  String toString() {
    if (this == G_APPLICATION_FLAGS_NONE)
      return "GApplicationFlags.G_APPLICATION_FLAGS_NONE, GApplicationFlags.G_APPLICATION_DEFAULT_FLAGS";
    return super.toString();
  }
}

/// GTlsError:
/// @G_TLS_ERROR_UNAVAILABLE: No TLS provider is available
/// @G_TLS_ERROR_MISC: Miscellaneous TLS error
/// @G_TLS_ERROR_BAD_CERTIFICATE: The certificate presented could not
/// be parsed or failed validation.
/// @G_TLS_ERROR_NOT_TLS: The TLS handshake failed because the
/// peer does not seem to be a TLS server.
/// @G_TLS_ERROR_HANDSHAKE: The TLS handshake failed because the
/// peer's certificate was not acceptable.
/// @G_TLS_ERROR_CERTIFICATE_REQUIRED: The TLS handshake failed because
/// the server requested a client-side certificate, but none was
/// provided. See g_tls_connection_set_certificate().
/// @G_TLS_ERROR_EOF: The TLS connection was closed without proper
/// notice, which may indicate an attack. See
/// g_tls_connection_set_require_close_notify().
/// @G_TLS_ERROR_INAPPROPRIATE_FALLBACK: The TLS handshake failed
/// because the client sent the fallback SCSV, indicating a protocol
/// downgrade attack. Since: 2.60
/// @G_TLS_ERROR_BAD_CERTIFICATE_PASSWORD: The certificate failed
/// to load because a password was incorrect. Since: 2.72
///
/// An error code used with %G_TLS_ERROR in a #GError returned from a
/// TLS-related routine.
///
/// Since: 2.28
enum GTlsError {
  G_TLS_ERROR_UNAVAILABLE(0),
  G_TLS_ERROR_MISC(1),
  G_TLS_ERROR_BAD_CERTIFICATE(2),
  G_TLS_ERROR_NOT_TLS(3),
  G_TLS_ERROR_HANDSHAKE(4),
  G_TLS_ERROR_CERTIFICATE_REQUIRED(5),
  G_TLS_ERROR_EOF(6),
  G_TLS_ERROR_INAPPROPRIATE_FALLBACK(7),
  G_TLS_ERROR_BAD_CERTIFICATE_PASSWORD(8);

  final int value;
  const GTlsError(this.value);

  static GTlsError fromValue(int value) => switch (value) {
    0 => G_TLS_ERROR_UNAVAILABLE,
    1 => G_TLS_ERROR_MISC,
    2 => G_TLS_ERROR_BAD_CERTIFICATE,
    3 => G_TLS_ERROR_NOT_TLS,
    4 => G_TLS_ERROR_HANDSHAKE,
    5 => G_TLS_ERROR_CERTIFICATE_REQUIRED,
    6 => G_TLS_ERROR_EOF,
    7 => G_TLS_ERROR_INAPPROPRIATE_FALLBACK,
    8 => G_TLS_ERROR_BAD_CERTIFICATE_PASSWORD,
    _ => throw ArgumentError("Unknown value for GTlsError: $value"),
  };
}

/// GTlsCertificateFlags:
/// @G_TLS_CERTIFICATE_NO_FLAGS: No flags set. Since: 2.74
/// @G_TLS_CERTIFICATE_UNKNOWN_CA: The signing certificate authority is
/// not known.
/// @G_TLS_CERTIFICATE_BAD_IDENTITY: The certificate does not match the
/// expected identity of the site that it was retrieved from.
/// @G_TLS_CERTIFICATE_NOT_ACTIVATED: The certificate's activation time
/// is still in the future
/// @G_TLS_CERTIFICATE_EXPIRED: The certificate has expired
/// @G_TLS_CERTIFICATE_REVOKED: The certificate has been revoked
/// according to the #GTlsConnection's certificate revocation list.
/// @G_TLS_CERTIFICATE_INSECURE: The certificate's algorithm is
/// considered insecure.
/// @G_TLS_CERTIFICATE_GENERIC_ERROR: Some other error occurred validating
/// the certificate
/// @G_TLS_CERTIFICATE_VALIDATE_ALL: the combination of all of the above
/// flags
///
/// A set of flags describing TLS certification validation. This can be
/// used to describe why a particular certificate was rejected (for
/// example, in #GTlsConnection::accept-certificate).
///
/// GLib guarantees that if certificate verification fails, at least one
/// flag will be set, but it does not guarantee that all possible flags
/// will be set. Accordingly, you may not safely decide to ignore any
/// particular type of error. For example, it would be incorrect to mask
/// %G_TLS_CERTIFICATE_EXPIRED if you want to allow expired certificates,
/// because this could potentially be the only error flag set even if
/// other problems exist with the certificate.
///
/// Since: 2.28
enum GTlsCertificateFlags {
  G_TLS_CERTIFICATE_NO_FLAGS(0),
  G_TLS_CERTIFICATE_UNKNOWN_CA(1),
  G_TLS_CERTIFICATE_BAD_IDENTITY(2),
  G_TLS_CERTIFICATE_NOT_ACTIVATED(4),
  G_TLS_CERTIFICATE_EXPIRED(8),
  G_TLS_CERTIFICATE_REVOKED(16),
  G_TLS_CERTIFICATE_INSECURE(32),
  G_TLS_CERTIFICATE_GENERIC_ERROR(64),
  G_TLS_CERTIFICATE_VALIDATE_ALL(127);

  final int value;
  const GTlsCertificateFlags(this.value);

  static GTlsCertificateFlags fromValue(int value) => switch (value) {
    0 => G_TLS_CERTIFICATE_NO_FLAGS,
    1 => G_TLS_CERTIFICATE_UNKNOWN_CA,
    2 => G_TLS_CERTIFICATE_BAD_IDENTITY,
    4 => G_TLS_CERTIFICATE_NOT_ACTIVATED,
    8 => G_TLS_CERTIFICATE_EXPIRED,
    16 => G_TLS_CERTIFICATE_REVOKED,
    32 => G_TLS_CERTIFICATE_INSECURE,
    64 => G_TLS_CERTIFICATE_GENERIC_ERROR,
    127 => G_TLS_CERTIFICATE_VALIDATE_ALL,
    _ => throw ArgumentError("Unknown value for GTlsCertificateFlags: $value"),
  };
}

