/// GSubprocessFlags:
/// @G_SUBPROCESS_FLAGS_NONE: No flags.
/// @G_SUBPROCESS_FLAGS_STDIN_PIPE: create a pipe for the stdin of the
/// spawned process that can be accessed with
/// g_subprocess_get_stdin_pipe().
/// @G_SUBPROCESS_FLAGS_STDIN_INHERIT: stdin is inherited from the
/// calling process.
/// @G_SUBPROCESS_FLAGS_STDOUT_PIPE: create a pipe for the stdout of the
/// spawned process that can be accessed with
/// g_subprocess_get_stdout_pipe().
/// @G_SUBPROCESS_FLAGS_STDOUT_SILENCE: silence the stdout of the spawned
/// process (ie: redirect to `/dev/null`).
/// @G_SUBPROCESS_FLAGS_STDERR_PIPE: create a pipe for the stderr of the
/// spawned process that can be accessed with
/// g_subprocess_get_stderr_pipe().
/// @G_SUBPROCESS_FLAGS_STDERR_SILENCE: silence the stderr of the spawned
/// process (ie: redirect to `/dev/null`).
/// @G_SUBPROCESS_FLAGS_STDERR_MERGE: merge the stderr of the spawned
/// process with whatever the stdout happens to be.  This is a good way
/// of directing both streams to a common log file, for example.
/// @G_SUBPROCESS_FLAGS_INHERIT_FDS: spawned processes will inherit the
/// file descriptors of their parent, unless those descriptors have
/// been explicitly marked as close-on-exec.  This flag has no effect
/// over the "standard" file descriptors (stdin, stdout, stderr).
/// @G_SUBPROCESS_FLAGS_SEARCH_PATH_FROM_ENVP: if path searching is
/// needed when spawning the subprocess, use the `PATH` in the launcher
/// environment. (Since: 2.72)
///
/// Flags to define the behaviour of a #GSubprocess.
///
/// Note that the default for stdin is to redirect from `/dev/null`.  For
/// stdout and stderr the default are for them to inherit the
/// corresponding descriptor from the calling process.
///
/// Note that it is a programmer error to mix 'incompatible' flags.  For
/// example, you may not request both %G_SUBPROCESS_FLAGS_STDOUT_PIPE and
/// %G_SUBPROCESS_FLAGS_STDOUT_SILENCE.
///
/// Since: 2.40
enum GSubprocessFlags {
  G_SUBPROCESS_FLAGS_NONE(0),
  G_SUBPROCESS_FLAGS_STDIN_PIPE(1),
  G_SUBPROCESS_FLAGS_STDIN_INHERIT(2),
  G_SUBPROCESS_FLAGS_STDOUT_PIPE(4),
  G_SUBPROCESS_FLAGS_STDOUT_SILENCE(8),
  G_SUBPROCESS_FLAGS_STDERR_PIPE(16),
  G_SUBPROCESS_FLAGS_STDERR_SILENCE(32),
  G_SUBPROCESS_FLAGS_STDERR_MERGE(64),
  G_SUBPROCESS_FLAGS_INHERIT_FDS(128),
  G_SUBPROCESS_FLAGS_SEARCH_PATH_FROM_ENVP(256);

  final int value;
  const GSubprocessFlags(this.value);

  static GSubprocessFlags fromValue(int value) => switch (value) {
    0 => G_SUBPROCESS_FLAGS_NONE,
    1 => G_SUBPROCESS_FLAGS_STDIN_PIPE,
    2 => G_SUBPROCESS_FLAGS_STDIN_INHERIT,
    4 => G_SUBPROCESS_FLAGS_STDOUT_PIPE,
    8 => G_SUBPROCESS_FLAGS_STDOUT_SILENCE,
    16 => G_SUBPROCESS_FLAGS_STDERR_PIPE,
    32 => G_SUBPROCESS_FLAGS_STDERR_SILENCE,
    64 => G_SUBPROCESS_FLAGS_STDERR_MERGE,
    128 => G_SUBPROCESS_FLAGS_INHERIT_FDS,
    256 => G_SUBPROCESS_FLAGS_SEARCH_PATH_FROM_ENVP,
    _ => throw ArgumentError("Unknown value for GSubprocessFlags: $value"),
  };
}

/// GNotificationPriority:
/// @G_NOTIFICATION_PRIORITY_LOW: for notifications that do not require
/// immediate attention - typically used for contextual background
/// information, such as contact birthdays or local weather
