  external GDBusInterfaceMethodCallFunc method_call;

  external GDBusInterfaceGetPropertyFunc get_property;

  external GDBusInterfaceSetPropertyFunc set_property;

  @ffi.Array.multi([8])
  external ffi.Array<gpointer> padding;
}

