/// GModuleFlags:
/// @G_MODULE_BIND_LAZY: specifies that symbols are only resolved when
/// needed. The default action is to bind all symbols when the module
/// is loaded.
/// @G_MODULE_BIND_LOCAL: specifies that symbols in the module should
/// not be added to the global name space. The default action on most
/// platforms is to place symbols in the module in the global name space,
/// which may cause conflicts with existing symbols.
/// @G_MODULE_BIND_MASK: mask for all flags.
///
/// Flags passed to g_module_open().
/// Note that these flags are not supported on all platforms.
enum GModuleFlags {
  G_MODULE_BIND_LAZY(1),
  G_MODULE_BIND_LOCAL(2),
  G_MODULE_BIND_MASK(3);

  final int value;
  const GModuleFlags(this.value);

  static GModuleFlags fromValue(int value) => switch (value) {
    1 => G_MODULE_BIND_LAZY,
    2 => G_MODULE_BIND_LOCAL,
    3 => G_MODULE_BIND_MASK,
    _ => throw ArgumentError("Unknown value for GModuleFlags: $value"),
  };
}

final class _GModule extends ffi.Opaque {}

/// GModuleError:
/// @G_MODULE_ERROR_FAILED: there was an error loading or opening a module file
/// @G_MODULE_ERROR_CHECK_FAILED: a module returned an error from its `g_module_check_init()` function
///
/// Errors returned by g_module_open_full().
///
/// Since: 2.70
enum GModuleError {
  G_MODULE_ERROR_FAILED(0),
  G_MODULE_ERROR_CHECK_FAILED(1);

  final int value;
  const GModuleError(this.value);

  static GModuleError fromValue(int value) => switch (value) {
    0 => G_MODULE_ERROR_FAILED,
    1 => G_MODULE_ERROR_CHECK_FAILED,
    _ => throw ArgumentError("Unknown value for GModuleError: $value"),
  };
}

