/// GSettingsBindFlags:
/// @G_SETTINGS_BIND_DEFAULT: Equivalent to `G_SETTINGS_BIND_GET|G_SETTINGS_BIND_SET`
/// @G_SETTINGS_BIND_GET: Update the #GObject property when the setting changes.
/// It is an error to use this flag if the property is not writable.
/// @G_SETTINGS_BIND_SET: Update the setting when the #GObject property changes.
/// It is an error to use this flag if the property is not readable.
/// @G_SETTINGS_BIND_NO_SENSITIVITY: Do not try to bind a "sensitivity" property to the writability of the setting
/// @G_SETTINGS_BIND_GET_NO_CHANGES: When set in addition to %G_SETTINGS_BIND_GET, set the #GObject property
/// value initially from the setting, but do not listen for changes of the setting
/// @G_SETTINGS_BIND_INVERT_BOOLEAN: When passed to g_settings_bind(), uses a pair of mapping functions that invert
/// the boolean value when mapping between the setting and the property.  The setting and property must both
/// be booleans.  You cannot pass this flag to g_settings_bind_with_mapping().
///
/// Flags used when creating a binding. These flags determine in which
/// direction the binding works. The default is to synchronize in both
/// directions.
enum GSettingsBindFlags {
  G_SETTINGS_BIND_DEFAULT(0),
  G_SETTINGS_BIND_GET(1),
  G_SETTINGS_BIND_SET(2),
  G_SETTINGS_BIND_NO_SENSITIVITY(4),
  G_SETTINGS_BIND_GET_NO_CHANGES(8),
  G_SETTINGS_BIND_INVERT_BOOLEAN(16);

  final int value;
  const GSettingsBindFlags(this.value);

  static GSettingsBindFlags fromValue(int value) => switch (value) {
    0 => G_SETTINGS_BIND_DEFAULT,
    1 => G_SETTINGS_BIND_GET,
    2 => G_SETTINGS_BIND_SET,
    4 => G_SETTINGS_BIND_NO_SENSITIVITY,
    8 => G_SETTINGS_BIND_GET_NO_CHANGES,
    16 => G_SETTINGS_BIND_INVERT_BOOLEAN,
    _ => throw ArgumentError("Unknown value for GSettingsBindFlags: $value"),
  };
}

