    17 => CAIRO_OPERATOR_DARKEN,
    18 => CAIRO_OPERATOR_LIGHTEN,
    19 => CAIRO_OPERATOR_COLOR_DODGE,
    20 => CAIRO_OPERATOR_COLOR_BURN,
    21 => CAIRO_OPERATOR_HARD_LIGHT,
    22 => CAIRO_OPERATOR_SOFT_LIGHT,
    23 => CAIRO_OPERATOR_DIFFERENCE,
